using System.Reactive.Linq;
using MeshWeaver.Application.Styles;
using MeshWeaver.Layout;
using MeshWeaver.Layout.Composition;
using MeshWeaver.Mesh;
using MeshWeaver.Mesh.Services;
using Microsoft.Extensions.DependencyInjection;

public record Story
{
    [Key]
    public string Id { get; init; } = string.Empty;

    [Required]
    public string Title { get; init; } = string.Empty;

    public string? Description { get; init; }

    /// <summary>
    /// The markdown content of the story.
    /// </summary>
    public string Markdown { get; init; } = string.Empty;

    public string IconName { get; init; } = "Document";

    public DateTimeOffset CreatedAt { get; init; } = DateTimeOffset.UtcNow;

    public DateTimeOffset? UpdatedAt { get; init; }

    // GitHub-style fields
    public string? Assignee { get; init; }
    public List<string>? Labels { get; init; }
    public string? Status { get; init; }  // Open, In Progress, Done
    public string? Milestone { get; init; }
    public List<string>? LinkedItems { get; init; }  // Paths to related nodes
}

/// <summary>
/// Layout views for Story nodes - GitHub issues-style layout.
/// </summary>
public static class StoryViews
{
    private const string StoryDataId = "story";
    private const string NodeDataId = "node";
    private const string ChildrenDataId = "children";

    /// <summary>
    /// Details view - GitHub issues-style layout with main content, comments, and sidebar.
    /// </summary>
    public static UiControl Details(LayoutAreaHost host, RenderingContext ctx)
    {
        var persistence = host.Hub.ServiceProvider.GetService<IPersistenceService>();
        var nodePath = host.Hub.Address.ToString();

        // Subscribe to story content
        host.SubscribeToDataStream(StoryDataId, host.Workspace.GetNodeContent<Story>());

        // Subscribe to node for metadata
        host.SubscribeToDataStream(NodeDataId, host.Workspace.GetStream<MeshNode>()
            .Select(nodes => nodes.FirstOrDefault(n => n.Path == nodePath)));

        // Subscribe to children (sub-stories)
        if (persistence != null)
        {
            host.SubscribeToDataStream(ChildrenDataId, 
                Observable.FromAsync(async () => 
                {
                    var children = new List<MeshNode>();
                    await foreach (var child in persistence.GetChildrenAsync(nodePath))
                    {
                        children.Add(child);
                    }
                    return children;
                }));
        }

        return Controls.Stack
            .WithWidth("100%")
            .WithView(
                (h, c) => h.GetDataStream<Story>(StoryDataId)
                    .CombineLatest(
                        h.GetDataStream<MeshNode>(NodeDataId),
                        h.GetDataStream<List<MeshNode>>(ChildrenDataId).StartWith(new List<MeshNode>()))
                    .Select(tuple =>
                    {
                        var (story, node, children) = tuple;
                        if (story == null)
                            return Controls.Progress("Loading...", 0);
                        return BuildGitHubStyleLayout(host, story, node, children ?? new List<MeshNode>());
                    }),
                "Content"
            );
    }

    private static UiControl BuildGitHubStyleLayout(
        LayoutAreaHost host, 
        Story story, 
        MeshNode? node,
        List<MeshNode> children)
    {
        var hubAddress = host.Hub.Address;
        var nodePath = node?.Path ?? hubAddress.ToString();

        // Main container with grid layout: 75% main, 25% sidebar
        var container = Controls.Stack
            .WithWidth("100%")
            .WithStyle("display: grid; grid-template-columns: 1fr 300px; gap: 24px; padding: 24px;");

        // ===== MAIN CONTENT AREA (Left) =====
        var mainContent = Controls.Stack.WithStyle("min-width: 0;");

        // Header with title and action buttons
        var headerRow = Controls.Stack
            .WithOrientation(Orientation.Horizontal)
            .WithStyle("justify-content: space-between; align-items: flex-start; margin-bottom: 16px; flex-wrap: wrap; gap: 12px;")
            .WithView(Controls.Html($"<h1 style=\"margin: 0; font-size: 2em;\">{System.Web.HttpUtility.HtmlEncode(story.Title)}</h1>"))
            .WithView(Controls.Stack
                .WithOrientation(Orientation.Horizontal)
                .WithStyle("gap: 8px;")
                .WithView(Controls.Button("Edit")
                    .WithAppearance(Appearance.Accent)
                    .WithIconStart(FluentIcons.Edit())
                    .WithClickAction(actx => actx.Host.UpdateArea(actx.Area, 
                        new RedirectControl(new LayoutAreaReference("Editor").ToHref(hubAddress))))));

        mainContent = mainContent.WithView(headerRow);

        // Description/subtitle
        if (!string.IsNullOrEmpty(story.Description))
        {
            mainContent = mainContent.WithView(Controls.Html(
                $"<p style=\"color: var(--neutral-foreground-hint); font-size: 1.1em; margin-bottom: 24px; border-bottom: 1px solid var(--neutral-stroke-divider); padding-bottom: 16px;\">" +
                $"{System.Web.HttpUtility.HtmlEncode(story.Description)}</p>"));
        }

        // Main markdown content
        if (!string.IsNullOrEmpty(story.Markdown))
        {
            mainContent = mainContent.WithView(new MarkdownControl(story.Markdown)
                .WithStyle("width: 100%; margin-bottom: 32px;"));
        }
        else
        {
            mainContent = mainContent.WithView(Controls.Html(
                "<p style=\"color: var(--neutral-foreground-hint); padding: 24px; background: var(--neutral-layer-2); border-radius: 8px;\">" +
                "No content yet. Click Edit to add content.</p>"));
        }

        // Divider before comments
        mainContent = mainContent.WithView(Controls.Html(
            "<hr style=\"border: none; border-top: 1px solid var(--neutral-stroke-divider); margin: 24px 0;\"/>"));

        // Comments section
        if (host.Hub.Configuration.HasComments())
        {
            mainContent = mainContent.WithView(Controls.Html("<h3 style=\"margin-bottom: 16px;\">Discussion</h3>"));
            mainContent = mainContent.WithView(CommentsView.BuildInlineCommentsSection(host));
        }

        container = container.WithView(mainContent);

        // ===== SIDEBAR (Right) =====
        var sidebar = Controls.Stack.WithStyle("position: sticky; top: 24px;");

        // Assignee section
        sidebar = sidebar.WithView(BuildSidebarSection("Assignee", 
            string.IsNullOrEmpty(story.Assignee) 
                ? "<span style=\"color: var(--neutral-foreground-hint);\">No one assigned</span>" 
                : $"<span>{System.Web.HttpUtility.HtmlEncode(story.Assignee)}</span>"));

        // Labels section
        var labelsHtml = "<span style=\"color: var(--neutral-foreground-hint);\">None yet</span>";
        if (story.Labels != null && story.Labels.Count > 0)
        {
            var labelBadges = string.Join(" ", story.Labels.Select(l => 
                $"<span style=\"background: var(--accent-fill-rest); color: var(--accent-foreground-cut); padding: 2px 8px; border-radius: 12px; font-size: 0.85em; margin-right: 4px;\">" +
                $"{System.Web.HttpUtility.HtmlEncode(l)}</span>"));
            labelsHtml = labelBadges;
        }
        sidebar = sidebar.WithView(BuildSidebarSection("Labels", labelsHtml));

        // Status section
        var statusBadge = string.IsNullOrEmpty(story.Status)
            ? "<span style=\"color: var(--neutral-foreground-hint);\">Not set</span>"
            : GetStatusBadge(story.Status);
        sidebar = sidebar.WithView(BuildSidebarSection("Status", statusBadge));

        // Milestone section
        sidebar = sidebar.WithView(BuildSidebarSection("Milestone",
            string.IsNullOrEmpty(story.Milestone)
                ? "<span style=\"color: var(--neutral-foreground-hint);\">No milestone</span>"
                : $"<span>{System.Web.HttpUtility.HtmlEncode(story.Milestone)}</span>"));

        // Parent story link (if this is a sub-story)
        if (node != null && !string.IsNullOrEmpty(node.ParentPath))
        {
            var parentName = node.ParentPath.Split('/').LastOrDefault() ?? node.ParentPath;
            sidebar = sidebar.WithView(BuildSidebarSection("Parent Story",
                $"<a href=\"/{node.ParentPath}\" style=\"color: var(--accent-foreground-rest); text-decoration: none;\">" +
                $"{System.Web.HttpUtility.HtmlEncode(parentName)}</a>"));
        }

        // Sub-stories section (children)
        if (children.Count > 0)
        {
            var subStoriesHtml = new System.Text.StringBuilder();
            subStoriesHtml.Append("<div style=\"display: flex; flex-direction: column; gap: 8px;\">");
            foreach (var child in children.Take(10))
            {
                var childName = child.Name ?? child.Id;
                subStoriesHtml.Append(
                    $"<a href=\"/{child.Path}\" style=\"color: var(--neutral-foreground-rest); text-decoration: none; padding: 8px; background: var(--neutral-layer-2); border-radius: 4px; display: block;\">" +
                    $"<span style=\"font-weight: 500;\">{System.Web.HttpUtility.HtmlEncode(childName)}</span>" +
                    (string.IsNullOrEmpty(child.Description) ? "" : 
                        $"<br/><span style=\"font-size: 0.85em; color: var(--neutral-foreground-hint);\">{System.Web.HttpUtility.HtmlEncode(child.Description.Length > 60 ? child.Description.Substring(0, 60) + "..." : child.Description)}</span>") +
                    "</a>");
            }
            if (children.Count > 10)
            {
                subStoriesHtml.Append($"<span style=\"color: var(--neutral-foreground-hint); font-size: 0.85em;\">+{children.Count - 10} more</span>");
            }
            subStoriesHtml.Append("</div>");
            sidebar = sidebar.WithView(BuildSidebarSection("Sub-stories", subStoriesHtml.ToString()));
        }

        // Linked items section
        if (story.LinkedItems != null && story.LinkedItems.Count > 0)
        {
            var linkedHtml = new System.Text.StringBuilder();
            linkedHtml.Append("<div style=\"display: flex; flex-direction: column; gap: 4px;\">");
            foreach (var linked in story.LinkedItems)
            {
                var linkedName = linked.Split('/').LastOrDefault() ?? linked;
                linkedHtml.Append(
                    $"<a href=\"/{linked}\" style=\"color: var(--accent-foreground-rest); text-decoration: none;\">" +
                    $"{System.Web.HttpUtility.HtmlEncode(linkedName)}</a>");
            }
            linkedHtml.Append("</div>");
            sidebar = sidebar.WithView(BuildSidebarSection("Linked Items", linkedHtml.ToString()));
        }

        // Metadata section (timestamps)
        var metaHtml = new System.Text.StringBuilder();
        metaHtml.Append($"<div style=\"font-size: 0.85em; color: var(--neutral-foreground-hint);\">");
        metaHtml.Append($"Created: {story.CreatedAt:MMM d, yyyy}");
        if (story.UpdatedAt.HasValue)
        {
            metaHtml.Append($"<br/>Updated: {story.UpdatedAt.Value:MMM d, yyyy}");
        }
        metaHtml.Append("</div>");
        sidebar = sidebar.WithView(BuildSidebarSection("Activity", metaHtml.ToString()));

        container = container.WithView(sidebar);

        return container;
    }

    private static UiControl BuildSidebarSection(string title, string contentHtml)
    {
        return Controls.Html(
            $"<div style=\"margin-bottom: 20px; padding-bottom: 16px; border-bottom: 1px solid var(--neutral-stroke-divider);\">" +
            $"<div style=\"font-weight: 600; font-size: 0.85em; color: var(--neutral-foreground-hint); margin-bottom: 8px; text-transform: uppercase;\">{title}</div>" +
            $"<div>{contentHtml}</div>" +
            "</div>");
    }

    private static string GetStatusBadge(string status)
    {
        var color = status.ToLowerInvariant() switch
        {
            "open" => "#238636",
            "in progress" => "#1f6feb",
            "done" => "#8b949e",
            "closed" => "#8b949e",
            _ => "#6e7681"
        };
        return $"<span style=\"background: {color}; color: white; padding: 4px 12px; border-radius: 12px; font-size: 0.85em;\">" +
               $"{System.Web.HttpUtility.HtmlEncode(status)}</span>";
    }

    /// <summary>
    /// Editor view - form for editing the story content and metadata.
    /// </summary>
    public static UiControl Editor(LayoutAreaHost host, RenderingContext ctx)
    {
        host.SubscribeToDataStream(StoryDataId, host.Workspace.GetNodeContent<Story>());

        return Controls.Stack
            .WithWidth("100%")
            .WithView(
                (h, c) => h.GetDataStream<Story>(StoryDataId)
                    .Select(story => BuildEditorContent(host, story)),
                "Editor"
            );
    }

    private static UiControl BuildEditorContent(LayoutAreaHost host, Story? story)
    {
        var hubAddress = host.Hub.Address;
        var stack = Controls.Stack.WithWidth("100%").WithStyle("padding: 24px; max-width: 900px;");

        // Generate unique IDs for form fields
        var titleDataId = Guid.NewGuid().ToString("N").Substring(0, 8);
        var descriptionDataId = Guid.NewGuid().ToString("N").Substring(0, 8);
        var markdownDataId = Guid.NewGuid().ToString("N").Substring(0, 8);
        var assigneeDataId = Guid.NewGuid().ToString("N").Substring(0, 8);
        var labelsDataId = Guid.NewGuid().ToString("N").Substring(0, 8);
        var statusDataId = Guid.NewGuid().ToString("N").Substring(0, 8);
        var milestoneDataId = Guid.NewGuid().ToString("N").Substring(0, 8);

        // Initialize data streams
        host.UpdateData(titleDataId, story?.Title ?? "");
        host.UpdateData(descriptionDataId, story?.Description ?? "");
        host.UpdateData(markdownDataId, story?.Markdown ?? "");
        host.UpdateData(assigneeDataId, story?.Assignee ?? "");
        host.UpdateData(labelsDataId, story?.Labels != null ? string.Join(", ", story.Labels) : "");
        host.UpdateData(statusDataId, story?.Status ?? "");
        host.UpdateData(milestoneDataId, story?.Milestone ?? "");

        stack = stack.WithView(Controls.Html("<h2 style=\"margin-bottom: 24px;\">Edit Story</h2>"));

        // Title
        stack = stack.WithView(BuildFormField("Title", titleDataId, "Enter title..."));

        // Description
        stack = stack.WithView(BuildFormField("Description", descriptionDataId, "Brief description..."));

        // Two-column layout for metadata fields
        stack = stack.WithView(Controls.Html("<div style=\"display: grid; grid-template-columns: 1fr 1fr; gap: 16px; margin-bottom: 16px;\">"));
        stack = stack.WithView(BuildFormFieldHtml("Assignee", assigneeDataId, "Assign to...", host));
        stack = stack.WithView(BuildFormFieldHtml("Status", statusDataId, "Open, In Progress, Done...", host));
        stack = stack.WithView(BuildFormFieldHtml("Labels", labelsDataId, "Comma-separated labels...", host));
        stack = stack.WithView(BuildFormFieldHtml("Milestone", milestoneDataId, "Milestone name...", host));
        stack = stack.WithView(Controls.Html("</div>"));

        // Markdown editor
        stack = stack.WithView(Controls.Html("<label style=\"font-weight: 500; display: block; margin-bottom: 8px; margin-top: 16px;\">Content (Markdown):</label>"));

        var editor = new CodeEditorControl()
            .WithLanguage("markdown")
            .WithHeight("400px")
            .WithLineNumbers(true)
            .WithMinimap(false)
            .WithWordWrap(true)
            .WithPlaceholder("Enter markdown content...") with
        {
            DataContext = LayoutAreaReference.GetDataPointer(markdownDataId),
            Value = new JsonPointerReference("")
        };
        stack = stack.WithView(editor);

        // Button row
        var buttonRow = Controls.Stack
            .WithOrientation(Orientation.Horizontal)
            .WithStyle("gap: 8px; margin-top: 24px;");

        // Save button
        buttonRow = buttonRow.WithView(Controls.Button("Save")
            .WithAppearance(Appearance.Accent)
            .WithIconStart(FluentIcons.Save())
            .WithClickAction(async actx =>
            {
                var currentTitle = await host.Stream.GetDataStream<string>(titleDataId).FirstAsync();
                var currentDescription = await host.Stream.GetDataStream<string>(descriptionDataId).FirstAsync();
                var currentMarkdown = await host.Stream.GetDataStream<string>(markdownDataId).FirstAsync();
                var currentAssignee = await host.Stream.GetDataStream<string>(assigneeDataId).FirstAsync();
                var currentLabels = await host.Stream.GetDataStream<string>(labelsDataId).FirstAsync();
                var currentStatus = await host.Stream.GetDataStream<string>(statusDataId).FirstAsync();
                var currentMilestone = await host.Stream.GetDataStream<string>(milestoneDataId).FirstAsync();

                // Parse labels from comma-separated string
                List<string>? labels = null;
                if (!string.IsNullOrWhiteSpace(currentLabels))
                {
                    labels = currentLabels.Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList();
                    if (labels.Count == 0) labels = null;
                }

                var updatedStory = (story ?? new Story()) with
                {
                    Title = currentTitle,
                    Description = string.IsNullOrWhiteSpace(currentDescription) ? null : currentDescription,
                    Markdown = currentMarkdown,
                    Assignee = string.IsNullOrWhiteSpace(currentAssignee) ? null : currentAssignee,
                    Labels = labels,
                    Status = string.IsNullOrWhiteSpace(currentStatus) ? null : currentStatus,
                    Milestone = string.IsNullOrWhiteSpace(currentMilestone) ? null : currentMilestone,
                    UpdatedAt = DateTimeOffset.UtcNow
                };

                using var cts = new CancellationTokenSource(10.Seconds());
                var response = await actx.Host.Hub.AwaitResponse<DataChangeResponse>(
                    new DataChangeRequest().WithUpdates(updatedStory),
                    o => o.WithTarget(hubAddress),
                    cts.Token);

                if (response.Message.Log.Status != ActivityStatus.Succeeded)
                {
                    var errorDialog = Controls.Dialog(
                        Controls.Markdown($"**Error saving story:**\n\n{response.Message.Log}"),
                        "Save Failed"
                    ).WithSize("M");
                    actx.Host.UpdateArea(DialogControl.DialogArea, errorDialog);
                    return;
                }

                var detailsHref = new LayoutAreaReference("Details").ToHref(hubAddress);
                actx.Host.UpdateArea(actx.Area, new RedirectControl(detailsHref));
            }));

        // Cancel button
        var detailsHref = new LayoutAreaReference("Details").ToHref(hubAddress);
        buttonRow = buttonRow.WithView(Controls.Button("Cancel")
            .WithAppearance(Appearance.Neutral)
            .WithClickAction(actx => actx.Host.UpdateArea(actx.Area, new RedirectControl(detailsHref))));

        stack = stack.WithView(buttonRow);

        return stack;
    }

    private static UiControl BuildFormField(string label, string dataId, string placeholder)
    {
        return Controls.Stack
            .WithStyle("margin-bottom: 16px;")
            .WithView(Controls.Html($"<label style=\"font-weight: 500; display: block; margin-bottom: 4px;\">{label}:</label>"))
            .WithView(new TextFieldControl(new JsonPointerReference(""))
                .WithPlaceholder(placeholder)
                .WithStyle("width: 100%;")
                .WithImmediate(true) with
            { DataContext = LayoutAreaReference.GetDataPointer(dataId) });
    }

    private static UiControl BuildFormFieldHtml(string label, string dataId, string placeholder, LayoutAreaHost host)
    {
        return Controls.Stack
            .WithView(Controls.Html($"<label style=\"font-weight: 500; display: block; margin-bottom: 4px;\">{label}:</label>"))
            .WithView(new TextFieldControl(new JsonPointerReference(""))
                .WithPlaceholder(placeholder)
                .WithStyle("width: 100%;")
                .WithImmediate(true) with
            { DataContext = LayoutAreaReference.GetDataPointer(dataId) });
    }
}
